import sys
import functools

def main():
    N = int(sys.stdin.readline())
    size = 3 ** N

    @functools.lru_cache(maxsize=None)
    def generate_carpet(k):
        if k == 0:
            return [["#"]]
        prev = generate_carpet(k - 1)
        size_prev = len(prev)
        carpet = []
        for i in range(3):
            for row in range(size_prev):
                new_row = []
                for j in range(3):
                    if i == 1 and j == 1:
                        new_row.extend(['.'] * size_prev)
                    else:
                        new_row.extend(prev[row])
                carpet.append(new_row)
        return carpet

    carpet = generate_carpet(N)
    for row in carpet:
        print(''.join(row))

if __name__ == "__main__":
    main()
